@layer base {
    :root {
      --background: 210 17% 98%;
      --background-foreground: 0 0% 4%;
      --background-foreground-muted: 0 0% 27%;
      --foreground: 0 0% 4%;

      --primary: 330 70% 83%;
      --primary-foreground: 0 0% 4%;
      --primary-foreground-muted: 328 12% 24%;

      --secondary: 190 82% 72%;
      --secondary-foreground: 0 0% 4%;
      --secondary-foreground-muted: 190 28% 21%;

      --neutral-1: 210 6% 94%;
      --neutral-2: 210 4% 89%;
      --neutral-3: 210 3% 85%;

      /* UI element colors */
      --card: 0 0% 100%;
      --card-foreground: 0 0% 4%;
      --card-foreground-muted: 0 0% 28%;

      --popover: 0 0% 100%;
      --popover-foreground: 0 0% 4%;
      --popover-foreground-muted: 0 0% 28%;

      --muted: 0 0% 87%;
      --muted-foreground: 0 0% 4%;
      --muted-foreground-muted: 0 0% 25%;

      --accent: 173 33% 95%;
      --accent-foreground: 0 0% 4%;
      --accent-foreground-muted: 180 1% 27%;

      --input: 210 9% 96%;
      --border: 210 9% 96%;
      --ring: 330 70% 83%;
      --ring-foreground: 0 0% 4%;
      --ring-foreground-muted: 328 12% 24%;

      /* State colors */
      --success: 152 69% 31%;
      --success-foreground: 0 0% 98%;
      --success-foreground-muted: 153 28% 81%;

      --warning: 45 100% 51%;
      --warning-foreground: 0 0% 4%;
      --warning-foreground-muted: 45 78% 16%;

      --destructive: 354 70% 54%;
      --destructive-foreground: 0 0% 98%;
      --destructive-foreground-muted: 354 64% 87%;
    }

    .dark {
      --background: 222.2 84% 4.9%;
      --foreground: 210 40% 98%;

      --card: 222.2 84% 4.9%;
      --card-foreground: 210 40% 98%;

      --popover: 222.2 84% 4.9%;
      --popover-foreground: 210 40% 98%;

      --primary: 210 40% 98%;
      --primary-foreground: 222.2 47.4% 11.2%;

      --secondary: 217.2 32.6% 17.5%;
      --secondary-foreground: 210 40% 98%;

      --muted: 217.2 32.6% 17.5%;
      --muted-foreground: 215 20.2% 65.1%;

      --accent: 217.2 32.6% 17.5%;
      --accent-foreground: 210 40% 98%;

      --destructive: 0 62.8% 30.6%;
      --destructive-foreground: 210 40% 98%;

      --border: 217.2 32.6% 17.5%;
      --input: 217.2 32.6% 17.5%;
      --ring: 212.7 26.8% 83.9%;
      --sidebar-background: 240 5.9% 10%;
      --sidebar-foreground: 240 4.8% 95.9%;
      --sidebar-primary: 224.3 76.3% 48%;
      --sidebar-primary-foreground: 0 0% 100%;
      --sidebar-accent: 240 3.7% 15.9%;
      --sidebar-accent-foreground: 240 4.8% 95.9%;
      --sidebar-border: 240 3.7% 15.9%;
      --sidebar-ring: 217.2 91.2% 59.8%;
    }
  }

  @layer base {
    * {
      @apply border-border;
    }

    body {
      @apply bg-background text-foreground;
      font-feature-settings: "rlig" 1, "calt" 1;
    }
  }

